/* ===================== MODULE TỰ DÒ KHUNG ẢNH =====================
   Khi admin upload ảnh trang, tự phân tích pixel để tìm vùng "trời xanh + đồi cỏ"
   (placeholder ảnh) và tạo khung chèn ảnh (toạ độ %). Chạy hoàn toàn bằng canvas trong trình duyệt. */
function morph(arr, w, h, dilate) {
  const out = new Uint8Array(w * h);
  for (let y = 0; y < h; y++) for (let x = 0; x < w; x++) {
    let v = dilate ? 0 : 1;
    for (let dy = -1; dy <= 1; dy++) for (let dx = -1; dx <= 1; dx++) {
      const nx = x + dx, ny = y + dy;
      const s = (nx >= 0 && ny >= 0 && nx < w && ny < h) ? arr[ny * w + nx] : 0;
      if (dilate) { if (s) v = 1; } else { if (!s) v = 0; }
    }
    out[y * w + x] = v;
  }
  return out;
}
function autoDetectSlots(src) {
  return new Promise((resolve) => {
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
      try {
        const MAX = 240, scale = Math.min(1, MAX / Math.max(img.width, img.height));
        const w = Math.max(1, Math.round(img.width * scale)), h = Math.max(1, Math.round(img.height * scale));
        const cv = document.createElement("canvas"); cv.width = w; cv.height = h;
        const ctx = cv.getContext("2d", { willReadFrequently: true });
        ctx.drawImage(img, 0, 0, w, h);
        const d = ctx.getImageData(0, 0, w, h).data, N = w * h;
        const sky = new Uint8Array(N), grass = new Uint8Array(N), place = new Uint8Array(N);
        for (let i = 0; i < N; i++) {
          const R = d[i * 4], G = d[i * 4 + 1], B = d[i * 4 + 2];
          const isSky = B >= 232 && G >= 205 && R >= 150 && B >= G && G > R;
          const isGrass = G > R && G > B && (G - B) > 30 && G > 110;
          sky[i] = isSky ? 1 : 0; grass[i] = isGrass ? 1 : 0; place[i] = (isSky || isGrass) ? 1 : 0;
        }
        const closed = morph(morph(place, w, h, true), w, h, false); // closing (sát mép placeholder, không hở)
        const lbl = new Int32Array(N), stack = [], slots = []; let cur = 0;
        for (let p = 0; p < N; p++) {
          if (!closed[p] || lbl[p]) continue;
          cur++; let area = 0, skc = 0, grc = 0, minx = w, maxx = 0, miny = h, maxy = 0;
          stack.push(p); lbl[p] = cur;
          while (stack.length) {
            const q = stack.pop(), qx = q % w, qy = (q / w) | 0;
            area++; if (sky[q]) skc++; if (grass[q]) grc++;
            if (qx < minx) minx = qx; if (qx > maxx) maxx = qx; if (qy < miny) miny = qy; if (qy > maxy) maxy = qy;
            for (let dy = -1; dy <= 1; dy++) for (let dx = -1; dx <= 1; dx++) {
              const nx = qx + dx, ny = qy + dy;
              if (nx < 0 || ny < 0 || nx >= w || ny >= h) continue;
              const np = ny * w + nx;
              if (closed[np] && !lbl[np]) { lbl[np] = cur; stack.push(np); }
            }
          }
          if (area < N * 0.008) continue;
          if (skc / area < 0.08 || grc / area < 0.05) continue;
          let bw = maxx - minx + 1, bh = maxy - miny + 1;
          // INSET 2.5% mỗi cạnh -> ảnh nằm gọn trong vùng, không lem viền trắng
          const mx = bw * 0.025, my = bh * 0.025;
          const ix = minx + mx, iy = miny + my, iw = bw - 2 * mx, ih = bh - 2 * my;
          slots.push({ x: +(ix / w * 100).toFixed(1), y: +(iy / h * 100).toFixed(1), w: +(iw / w * 100).toFixed(1), h: +(ih / h * 100).toFixed(1), shape: "rect" });
        }
        slots.sort((a, b) => (a.y - b.y) || (a.x - b.x));
        resolve(slots);
      } catch (e) { resolve([]); }
    };
    img.onerror = () => resolve([]);
    img.src = src;
  });
}

/* Sinh bố cục trang + toạ độ khung ảnh (mô phỏng "vùng ảnh mẫu" của template).
   Trang trí (nền, khung, caption) là cố định; chỉ phần trong khung là thay được. */
function buildPages(t) {
  // MẪU THẬT: pages là mảng { image, slots:[{x,y,w,h,shape}] } -> dùng trực tiếp, gán g toàn cục
  if (Array.isArray(t.pages) && t.pages.length && t.pages[0] && typeof t.pages[0] === "object" && t.pages[0].image) {
    let g = 0;
    return t.pages.map((p) => ({
      image: p.image, grad: t.grad, caption: "",
      slots: (p.slots || []).map((s) => ({ ...s, g: g++ })),
    }));
  }
  // MẪU TẠO TỪ SỐ KHUNG (fallback)
  const total = Math.max(1, t.slots || 4);
  const pages = [];
  let g = 0, remaining = total, idx = 0;
  while (remaining > 0) {
    const n = Math.min(2, remaining);
    const slots = n === 1
      ? [{ g: g++, x: 12, y: 14, w: 76, h: 64 }]
      : [{ g: g++, x: 7, y: 12, w: 41, h: 70 }, { g: g++, x: 52, y: 12, w: 41, h: 70 }];
    pages.push({ grad: t.grad, caption: idx === 0 ? t.title : `Trang ${idx + 1}`, slots });
    remaining -= n; idx++;
  }
  return pages;
}

