/* Bộ lọc màu nhẹ cho ảnh trong khung */
const FILTERS = {
  none: "none",
  warm: "saturate(1.18) sepia(.16) brightness(1.03)",
  cool: "saturate(1.1) hue-rotate(-12deg) brightness(1.02)",
  bw: "grayscale(1) contrast(1.06)",
  vivid: "saturate(1.55) contrast(1.08)",
  soft: "contrast(.94) brightness(1.06) saturate(.92)",
};
const FILTER_LABELS = [["none", "Gốc"], ["warm", "Ấm"], ["cool", "Lạnh"], ["vivid", "Tươi"], ["soft", "Dịu"], ["bw", "Đen trắng"]];
const imgStyle = (e) => ({
  width: "100%", height: "100%", objectFit: "cover",
  objectPosition: `${e?.ox ?? 50}% ${e?.oy ?? 50}%`,
  transform: `scale(${e?.scale ?? 1}) rotate(${e?.rot ?? 0}deg)`,
  filter: FILTERS[e?.filter || "none"], transition: "filter .2s ease",
});

/* Một trang photobook: nền ảnh thật + khung ảnh (thay/chỉnh/kéo ra) + text di chuyển được. */
function PageView({ page, assignments, edits, sample, onSlot, selected, editSlot, onAdjust,
                   texts, onTextMove, onTextSelect, selText, onPhotoDragStart, onPhotoDragEnd, fill }) {
  const draggedRef = useRef(0);
  const rootRef = useRef();
  const startDrag = (s, ev) => {
    if (editSlot !== s.g || !onAdjust || !assignments?.[s.g]) return;
    ev.stopPropagation(); ev.preventDefault();
    const cur = edits?.[s.g] || {};
    const sx = ev.clientX, sy = ev.clientY, ox = cur.ox ?? 50, oy = cur.oy ?? 50;
    let moved = false;
    const move = (e) => {
      const dx = e.clientX - sx, dy = e.clientY - sy;
      if (Math.abs(dx) + Math.abs(dy) > 3) moved = true;
      onAdjust(s.g, { ox: Math.min(100, Math.max(0, ox - dx * 0.25)), oy: Math.min(100, Math.max(0, oy - dy * 0.25)) });
    };
    const up = () => { document.removeEventListener("pointermove", move); document.removeEventListener("pointerup", up); if (moved) draggedRef.current = Date.now(); };
    document.addEventListener("pointermove", move); document.addEventListener("pointerup", up);
  };
  const startTextDrag = (tx, ev) => {
    if (!onTextMove) return; ev.stopPropagation();
    const rect = rootRef.current.getBoundingClientRect();
    const move = (e) => {
      const x = ((e.clientX - rect.left) / rect.width) * 100, y = ((e.clientY - rect.top) / rect.height) * 100;
      onTextMove(tx.id, { x: Math.max(2, Math.min(98, x)), y: Math.max(3, Math.min(97, y)) });
    };
    const up = () => { document.removeEventListener("pointermove", move); document.removeEventListener("pointerup", up); };
    document.addEventListener("pointermove", move); document.addEventListener("pointerup", up);
  };
  const real = !!page.image;
  return (
    <div ref={rootRef} style={{ position: "relative", width: "100%", height: fill ? "100%" : undefined, aspectRatio: fill ? undefined : (real ? "2000/1300" : "4/3"), borderRadius: fill ? 0 : 12, overflow: "hidden", background: real ? "#fff" : `linear-gradient(135deg, ${page.grad[0]}, ${page.grad[1]})`, boxShadow: fill ? "none" : "0 10px 30px rgba(42,37,32,.14)" }}>
      {real && <img src={page.image} draggable={false} style={{ position: "absolute", inset: 0, width: "100%", height: "100%", objectFit: "cover", userSelect: "none", pointerEvents: "none" }} />}
      {!real && <div style={{ position: "absolute", inset: 10, border: "2px solid rgba(255,255,255,.6)", borderRadius: 8, pointerEvents: "none" }} />}
      {!real && page.caption && <div style={{ position: "absolute", left: 0, right: 0, bottom: 10, textAlign: "center", fontFamily: serif, color: "#fff", fontSize: 15, fontWeight: 600, textShadow: "0 1px 5px rgba(0,0,0,.3)", pointerEvents: "none", padding: "0 12px", zIndex: 5 }}>{page.caption}</div>}

      {page.slots.map((s) => {
        const img = assignments?.[s.g];
        const sel = selected === s.g;
        const editable = editSlot === s.g && !!img && !!onAdjust;
        const round = s.shape === "circle";
        const canDragOut = !!onSlot && !!img && !sel; // kéo ảnh ra khi khung chưa được chọn
        return (
          <div key={s.g}
            onClick={onSlot ? () => { if (Date.now() - draggedRef.current < 200) return; onSlot(s.g); } : undefined}
            onPointerDown={editable ? (e) => startDrag(s, e) : undefined}
            onDragOver={onSlot ? (e) => e.preventDefault() : undefined}
            onDrop={onSlot ? (e) => { e.preventDefault(); const u = e.dataTransfer.getData("text/mm"); const fr = e.dataTransfer.getData("text/mm-from"); if (u) onSlot(s.g, u); else if (fr !== "") onSlot(s.g, { move: +fr }); } : undefined}
            style={{
              position: "absolute", left: s.x + "%", top: s.y + "%", width: s.w + "%", height: s.h + "%",
              borderRadius: round ? "50%" : 3, overflow: "hidden", cursor: editable ? "move" : (onSlot ? "pointer" : "default"),
              border: sel ? `3px solid ${C.brass}` : img ? "none" : (real ? "2px dashed rgba(176,141,87,.9)" : "2px solid rgba(255,255,255,.85)"),
              background: img ? "transparent" : (real ? "rgba(255,255,255,.14)" : "rgba(255,255,255,.4)"),
              display: "grid", placeItems: "center", boxShadow: sel ? "0 0 0 3px rgba(176,141,87,.3)" : "none", zIndex: 3,
            }}>
            {img
              ? <img src={img} draggable={canDragOut}
                  onDragStart={canDragOut ? (e) => { e.dataTransfer.setData("text/mm-from", String(s.g)); onPhotoDragStart && onPhotoDragStart(s.g); } : undefined}
                  onDragEnd={canDragOut ? () => onPhotoDragEnd && onPhotoDragEnd(s.g) : undefined}
                  style={imgStyle(edits?.[s.g])} />
              : (onSlot ? <div style={{ textAlign: "center", color: real ? C.brass : "rgba(42,37,32,.55)", fontFamily: sans, fontSize: 11 }}>
                  <ImageIcon size={16} /><div>{sample ? "Ảnh mẫu" : "Chèn ảnh"}</div>
                </div> : null)}
          </div>
        );
      })}

      {/* TEXT người dùng thêm */}
      {(texts || []).map((tx) => (
        <div key={tx.id}
          onPointerDown={onTextMove ? (e) => startTextDrag(tx, e) : undefined}
          onClick={onTextSelect ? (e) => { e.stopPropagation(); onTextSelect(tx.id); } : undefined}
          style={{
            position: "absolute", left: tx.x + "%", top: tx.y + "%", transform: "translate(-50%,-50%)",
            fontFamily: tx.font === "sans" ? sans : serif, fontSize: tx.size || 20, color: tx.color || "#2A2520",
            fontWeight: 600, whiteSpace: "pre", maxWidth: "90%", textAlign: "center", lineHeight: 1.2,
            cursor: onTextMove ? "move" : "default", userSelect: "none", zIndex: 6,
            padding: "2px 6px", borderRadius: 5,
            border: selText === tx.id ? `1.5px dashed ${C.brass}` : "1.5px solid transparent",
            textShadow: "0 1px 3px rgba(255,255,255,.45)",
          }}>{tx.text || "Nhập chữ"}</div>
      ))}
    </div>
  );
}

/* Trang trắng (bìa/lót) khi index ngoài phạm vi */
function BlankPage({ label }) {
  return <div style={{ width: "100%", height: "100%", background: `linear-gradient(135deg, ${C.cream2}, #fff)`, display: "grid", placeItems: "center" }}>
    <div style={{ textAlign: "center", color: C.sub, fontFamily: serif, fontStyle: "italic", fontSize: 18, opacity: .6 }}>{label || "Memory Makers"}</div>
  </div>;
}

/* Lõi cuốn sách: 2 trang/spread, LẬT TRANG CONG 3D có bóng đổ như sách thật.
   Bìa trước đứng một mình (nửa phải, trái trống); bìa sau CHỈ có khi tổng trang hiển thị CHẴN. */
function BookCore({ t, assignments, edits, texts, hidden, sample, big }) {
  const seq = useMemo(() => {
    const all = buildPages(t).map((p, i) => ({ ...p, texts: (texts && texts[i]) || [] }));
    const vis = all.filter((_, i) => !(hidden && hidden[i]));
    const n = vis.length;
    if (!n) return [];
    const even = n % 2 === 0 && n > 1;
    const front = vis[0]; const back = even ? vis[n - 1] : null;
    const inner = vis.slice(1, even ? n - 1 : n);
    const s = [null, front, ...inner];
    if (back) { s.push(back, null); }
    if (s.length % 2) s.push(null);
    return s;
  }, [t, texts, hidden]);

  const count = seq.length;
  const [spread, setSpread] = useState(0);
  const [anim, setAnim] = useState(null);
  useEffect(() => { setSpread(s => Math.min(s, Math.max(0, count - 2))); }, [count]);
  const busy = anim !== null;
  const renderPage = (i) => seq[i] ? <PageView page={seq[i]} assignments={assignments} edits={edits} texts={seq[i].texts} sample={sample} fill /> : <BlankPage />;

  const go = (dir) => {
    if (busy) return;
    if (dir === "next" && spread + 2 >= count) return;
    if (dir === "prev" && spread <= 0) return;
    setAnim({ dir, started: false });
    requestAnimationFrame(() => requestAnimationFrame(() => setAnim(a => a && { ...a, started: true })));
    setTimeout(() => { setSpread(s => dir === "next" ? s + 2 : s - 2); setAnim(null); }, 720);
  };

  let L = spread, R = spread + 1, leaf = null;
  if (anim?.dir === "next") { R = spread + 3; leaf = { side: "right", front: spread + 1, back: spread + 2, target: -180 }; }
  if (anim?.dir === "prev") { L = spread - 2; leaf = { side: "left", front: spread, back: spread - 1, target: 180 }; }
  const turning = anim?.started;
  const half = { position: "absolute", top: 0, width: "50%", height: "100%", overflow: "hidden" };
  const spineShadow = (side) => ({ position: "absolute", top: 0, bottom: 0, [side]: 0, width: "12%", pointerEvents: "none", background: side === "left" ? "linear-gradient(to right, rgba(0,0,0,.16), transparent)" : "linear-gradient(to left, rgba(0,0,0,.16), transparent)" });
  if (!count) return <div style={{ aspectRatio: "40/13", display: "grid", placeItems: "center", background: C.cream2, borderRadius: 12, fontFamily: sans, color: C.sub, fontSize: 13 }}>Tất cả trang đang bị ẩn.</div>;

  return (
    <div>
      <div style={{ perspective: big ? 3000 : 2200 }}>
        <div style={{ position: "relative", width: "100%", aspectRatio: "40/13", borderRadius: 12, background: "#EFE7DA", boxShadow: "0 24px 60px rgba(42,37,32,.28)", transformStyle: "preserve-3d" }}>
          <div style={{ ...half, left: 0, borderRight: "1px solid rgba(0,0,0,.06)" }}>{renderPage(L)}<div style={spineShadow("right")} /></div>
          <div style={{ ...half, left: "50%" }}>{renderPage(R)}<div style={spineShadow("left")} /></div>
          {leaf && (
            <div style={{ position: "absolute", top: 0, height: "100%", width: "50%", [leaf.side === "right" ? "left" : "right"]: "50%", transformStyle: "preserve-3d", transformOrigin: leaf.side === "right" ? "left center" : "right center", transform: `rotateY(${turning ? leaf.target : 0}deg)`, transition: "transform .72s cubic-bezier(.42,.05,.25,1)", zIndex: 5 }}>
              <div style={{ position: "absolute", inset: 0, backfaceVisibility: "hidden", overflow: "hidden" }}>{renderPage(leaf.front)}<div style={spineShadow(leaf.side === "right" ? "left" : "right")} /><div className={turning ? "mm-shade" : ""} style={{ position: "absolute", inset: 0, opacity: 0, background: `linear-gradient(${leaf.side === "right" ? "to right" : "to left"}, rgba(0,0,0,.5), transparent 60%)` }} /></div>
              <div style={{ position: "absolute", inset: 0, backfaceVisibility: "hidden", transform: "rotateY(180deg)", overflow: "hidden" }}>{renderPage(leaf.back)}<div style={spineShadow(leaf.side === "right" ? "right" : "left")} /><div className={turning ? "mm-shade" : ""} style={{ position: "absolute", inset: 0, opacity: 0, background: `linear-gradient(${leaf.side === "right" ? "to left" : "to right"}, rgba(0,0,0,.4), transparent 60%)` }} /></div>
            </div>
          )}
          <div style={{ position: "absolute", top: 0, bottom: 0, left: "calc(50% - 1px)", width: 2, background: "rgba(42,37,32,.12)", zIndex: 6, pointerEvents: "none" }} />
        </div>
      </div>
      <div style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 18, marginTop: 14 }}>
        <button onClick={() => go("prev")} disabled={spread <= 0 || busy} className="mm-arrow" style={{ ...arrowBtn, width: 38, height: 38, opacity: spread <= 0 ? .35 : 1 }}><ChevronLeft size={18} color={C.ink} /></button>
        <span style={{ fontFamily: sans, fontSize: 12, letterSpacing: 1.5, color: C.sub, textTransform: "uppercase", minWidth: 150, textAlign: "center" }}>Trang {spread + 1}–{Math.min(spread + 2, count)} / {count}</span>
        <button onClick={() => go("next")} disabled={spread + 2 >= count || busy} className="mm-arrow" style={{ ...arrowBtn, width: 38, height: 38, opacity: spread + 2 >= count ? .35 : 1 }}><ChevronRight size={18} color={C.ink} /></button>
      </div>
    </div>
  );
}

/* Flipbook: khung "Interactive Preview" + nút Open Flipbook (toàn màn hình) + watermark. */
function Flipbook({ t, assignments, edits, texts, hidden, sample, watermark }) {
  const [full, setFull] = useState(false);
  const [blurGuard, setBlurGuard] = useState(false);
  useEffect(() => {
    if (!watermark) return;
    const onVis = () => setBlurGuard(document.hidden);
    const hide = () => setBlurGuard(true); const show = () => setBlurGuard(false);
    window.addEventListener("blur", hide); window.addEventListener("focus", show); document.addEventListener("visibilitychange", onVis);
    return () => { window.removeEventListener("blur", hide); window.removeEventListener("focus", show); document.removeEventListener("visibilitychange", onVis); };
  }, [watermark]);
  const overlay = watermark && (
    <>
      <div style={{ position: "absolute", inset: 0, pointerEvents: "none", display: "flex", flexWrap: "wrap", gap: 24, alignContent: "center", justifyContent: "center", opacity: .13, transform: "rotate(-22deg)", zIndex: 8 }}>
        {Array.from({ length: 14 }).map((_, k) => <span key={k} style={{ fontFamily: sans, fontWeight: 800, fontSize: 15, whiteSpace: "nowrap" }}>MEMORY MAKERS · CHƯA THANH TOÁN</span>)}
      </div>
      {blurGuard && <div style={{ position: "absolute", inset: 0, background: C.ink, display: "grid", placeItems: "center", color: "#fff", fontFamily: sans, zIndex: 9, borderRadius: 12 }}><div style={{ textAlign: "center" }}><EyeOff size={30} /><div style={{ marginTop: 8, fontSize: 13 }}>Tạm ẩn để bảo vệ bản quyền</div></div></div>}
    </>
  );
  return (
    <div onContextMenu={e => e.preventDefault()} style={{ userSelect: "none" }}>
      <div style={{ background: C.card, border: `1px solid ${C.line}`, borderRadius: 16, padding: 16 }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 12 }}>
          <span style={{ fontFamily: sans, fontSize: 11, letterSpacing: 1.5, textTransform: "uppercase", color: C.sub, fontWeight: 700, display: "flex", gap: 6, alignItems: "center" }}><BookOpen size={14} color={C.brass} /> Interactive Preview</span>
          <button onClick={() => setFull(true)} className="mm-btn" style={{ display: "flex", gap: 6, alignItems: "center", fontFamily: sans, fontSize: 12, fontWeight: 600, color: C.ink, background: C.cream2, border: `1px solid ${C.line}`, borderRadius: 999, padding: "6px 13px", cursor: "pointer" }}><Layers size={13} /> Open Flipbook</button>
        </div>
        <div style={{ position: "relative" }}><BookCore t={t} assignments={assignments} edits={edits} texts={texts} hidden={hidden} sample={sample} />{overlay}</div>
      </div>

      {full && (
        <div onClick={() => setFull(false)} style={{ position: "fixed", inset: 0, background: "rgba(28,24,20,.92)", zIndex: 90, display: "grid", placeItems: "center", padding: 28, animation: "mmFadeIn .25s ease" }}>
          <button onClick={() => setFull(false)} style={{ position: "absolute", top: 18, right: 20, background: "rgba(255,255,255,.15)", border: "none", borderRadius: "50%", width: 40, height: 40, display: "grid", placeItems: "center", cursor: "pointer" }}><X size={20} color="#fff" /></button>
          <div onClick={e => e.stopPropagation()} style={{ width: "min(1100px, 94vw)" }}>
            <div style={{ position: "relative" }}><BookCore t={t} assignments={assignments} edits={edits} texts={texts} hidden={hidden} sample={sample} big />{overlay}</div>
          </div>
        </div>
      )}
    </div>
  );
}
const arrowBtn = { width: 44, height: 44, borderRadius: "50%", background: C.card, border: `1px solid ${C.line}`, display: "grid", placeItems: "center", cursor: "pointer", flexShrink: 0, zIndex: 2 };

/* ===================== AI MATCHING + MODAL ===================== */
const THEME_HINTS = {
  "du lịch": ["du lịch", "biển", "travel", "phượt", "chuyến đi", "đi chơi", "lữ khách", "beach", "sea", "núi", "khám phá", "vi vu"],
  "tình yêu": ["tình yêu", "người yêu", "cặp đôi", "couple", "hẹn hò", "valentine", "crush", "anniversary"],
  "cưới": ["cưới", "đám cưới", "wedding", "cô dâu", "chú rể", "đính hôn", "vu quy"],
  "gia đình": ["gia đình", "bố", "mẹ", "ba", "con", "family", "ông", "bà", "nhà mình"],
  "sinh nhật": ["sinh nhật", "birthday", "tiệc", "thổi nến", "bánh kem", "mừng tuổi"],
  "tốt nghiệp": ["tốt nghiệp", "ra trường", "kỷ yếu", "graduation", "cử nhân", "lớp"],
  "bạn bè": ["bạn bè", "nhóm bạn", "friends", "hội", "đám bạn", "team"],
  "kỷ niệm": ["kỷ niệm", "khoảnh khắc", "memory", "lưu giữ", "hồi ức", "dấu ấn"],
};
function matchTemplates(prompt, templates) {
  const text = (prompt || "").toLowerCase();
  return templates.map((t) => {
    let score = 0;
    for (const w of t.keywords) if (text.includes(w)) score += 3;
    for (const [canon, hints] of Object.entries(THEME_HINTS)) {
      if (hints.some((h) => text.includes(h)) && t.keywords.includes(canon)) score += 4;
    }
    for (const word of t.title.toLowerCase().split(/\s+/)) if (word.length > 2 && text.includes(word)) score += 1;
    return { t, score };
  }).sort((a, b) => b.score - a.score);
}

function AIDesignModal({ templates, initialPrompt, onUse, onClose }) {
  const [prompt, setPrompt] = useState(initialPrompt || "");
  const [thinking, setThinking] = useState(false);
  const [results, setResults] = useState(null);
  const EXAMPLES = ["Tôi muốn mẫu đi du lịch biển cùng người yêu", "Album cưới phong cách nhẹ nhàng", "Kỷ yếu tốt nghiệp cho nhóm bạn", "Sinh nhật bé 1 tuổi thật dễ thương"];
  const run = (text) => {
    const q = (text ?? prompt).trim(); if (!q) return;
    setThinking(true); setResults(null);
    setTimeout(() => {
      const scored = matchTemplates(q, templates).filter((s) => s.score > 0).slice(0, 3).map((s) => s.t);
      setResults(scored.length ? scored : [templates.find((t) => t.featured) || templates[0]]); setThinking(false);
    }, 450);
  };
  useEffect(() => { if (initialPrompt && initialPrompt.trim()) run(initialPrompt); /* eslint-disable-next-line */ }, []);
  return (
    <div onClick={onClose} style={{ position: "fixed", inset: 0, background: "rgba(42,37,32,.5)", backdropFilter: "blur(3px)", zIndex: 80, display: "grid", placeItems: "center", padding: 20, animation: "mmFadeIn .25s ease" }}>
      <div onClick={(e) => e.stopPropagation()} className="mm-pop" style={{ width: "100%", maxWidth: 560, background: C.paper, borderRadius: 22, border: `1px solid ${C.line}`, overflow: "hidden", boxShadow: "0 30px 80px rgba(42,37,32,.3)" }}>
        <div style={{ background: `linear-gradient(120deg, ${C.blush}, ${C.brass})`, padding: "20px 24px", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
          <div style={{ display: "flex", gap: 11, alignItems: "center" }}>
            <div style={{ width: 38, height: 38, borderRadius: 11, background: "rgba(255,255,255,.25)", display: "grid", placeItems: "center" }}><Wand2 size={20} color="#fff" /></div>
            <div><div style={{ fontFamily: serif, fontSize: 20, color: "#fff", fontWeight: 700 }}>Thiết kế với AI</div><div style={{ fontFamily: sans, fontSize: 12, color: "rgba(255,255,255,.9)" }}>Mô tả mẫu — AI chọn giúp bạn</div></div>
          </div>
          <button onClick={onClose} style={{ background: "rgba(255,255,255,.2)", border: "none", borderRadius: "50%", width: 32, height: 32, display: "grid", placeItems: "center", cursor: "pointer" }}><X size={17} color="#fff" /></button>
        </div>
        <div style={{ padding: 24 }}>
          <p style={{ fontFamily: sans, fontSize: 14, color: C.sub, margin: "0 0 12px" }}>Mô tả câu chuyện bạn muốn kể, AI sẽ tìm mẫu hợp nhất rồi đưa bạn vào trình thiết kế.</p>
          <textarea value={prompt} onChange={(e) => setPrompt(e.target.value)} rows={3} placeholder="Ví dụ: tôi muốn mẫu đi du lịch biển cùng người yêu"
            style={{ width: "100%", padding: 14, borderRadius: 14, border: `1.5px solid ${C.line}`, fontFamily: sans, fontSize: 15, color: C.ink, outline: "none", resize: "vertical", lineHeight: 1.6, boxSizing: "border-box" }} />
          <div style={{ display: "flex", flexWrap: "wrap", gap: 8, margin: "12px 0 16px" }}>
            {EXAMPLES.map((ex) => <button key={ex} onClick={() => setPrompt(ex)} style={{ fontFamily: sans, fontSize: 12.5, color: C.sub, background: C.cream2, border: `1px solid ${C.line}`, borderRadius: 999, padding: "6px 13px", cursor: "pointer" }}>{ex}</button>)}
          </div>
          <Btn full variant="brass" icon={Sparkles} onClick={() => run()} disabled={!prompt.trim() || thinking}>{thinking ? "AI đang chọn mẫu…" : "Tạo mẫu với AI"}</Btn>
          {thinking && <div style={{ textAlign: "center", padding: "22px 0 4px" }}><div style={{ width: 44, height: 44, border: `4px solid ${C.cream2}`, borderTopColor: C.brass, borderRadius: "50%", margin: "0 auto", animation: "mmspin 1s linear infinite" }} /><style>{`@keyframes mmspin{to{transform:rotate(360deg)}}`}</style></div>}
          {results && (
            <div className="mm-rise" style={{ marginTop: 18 }}>
              <div style={{ fontFamily: sans, fontSize: 13, color: C.sub, marginBottom: 10 }}>AI gợi ý {results.length} mẫu — chọn để vào thiết kế:</div>
              <div style={{ display: "grid", gridTemplateColumns: "repeat(3,1fr)", gap: 12 }}>
                {results.map((t) => (
                  <button key={t.id} onClick={() => onUse(t)} className="mm-card" style={{ background: C.card, border: `1px solid ${C.line}`, borderRadius: 14, padding: 8, cursor: "pointer", textAlign: "left" }}>
                    <Cover t={t} kind="cover" />
                    <div style={{ fontFamily: serif, fontSize: 14, color: C.ink, fontWeight: 600, marginTop: 8 }}>{t.title}</div>
                    <div style={{ fontFamily: sans, fontSize: 12, color: C.brass, fontWeight: 600, marginTop: 4, display: "flex", alignItems: "center", gap: 4 }}><Wand2 size={12} /> Thiết kế ngay</div>
                  </button>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

