/* ===================== GALLERY ===================== */
// màu nhãn danh mục theo chủ đề
const CAT_COLORS = {
  "Kỷ niệm": ["#F6D9E0", "#B05A7A"], "Du lịch": ["#CFE8DD", "#2E8B6E"], "Gia đình": ["#E8E1D2", "#7A6A4F"],
  "Tốt nghiệp": ["#E2D7F2", "#7A57B0"], "Tình yêu": ["#F8D5DD", "#C44E73"], "Cưới": ["#F3E3D2", "#B0833F"],
  "Bạn bè": ["#D7E6F2", "#3E7CB0"], "Sinh nhật": ["#FBE3CF", "#C77A33"],
};
const PRICE_COLORS = ["#C44E73", "#2E8B6E", "#C77A33", "#7A57B0", "#3E7CB0", "#B05A7A"];

/* Bìa "sách mở" có mũi tên lật + nút play + chấm trang (mini preview). */
function GalleryCover({ t, onPlay }) {
  const pages = useMemo(() => { const p = buildPages(t); if (p.length % 2) p.push(null); return p; }, [t]);
  const spreads = Math.max(1, pages.length / 2);
  const [s, setS] = useState(0);
  const move = (d, e) => { e.stopPropagation(); setS(v => (v + d + spreads) % spreads); };
  const miniPage = (idx, side) => {
    const pg = pages[idx];
    if (!pg) return <div style={{ flex: 1, background: `linear-gradient(135deg, ${C.cream2}, #fff)` }} />;
    if (pg.image) return (
      <div style={{ flex: 1, position: "relative", overflow: "hidden" }}>
        <img src={pg.image} draggable={false} style={{ width: "100%", height: "100%", objectFit: "cover" }} />
        <div style={{ position: "absolute", top: 0, bottom: 0, [side === "left" ? "right" : "left"]: 0, width: "16%", background: side === "left" ? "linear-gradient(to left, rgba(0,0,0,.16), transparent)" : "linear-gradient(to right, rgba(0,0,0,.16), transparent)" }} />
      </div>
    );
    const two = pg.slots.length > 1;
    return (
      <div style={{ flex: 1, position: "relative", background: `linear-gradient(135deg, ${pg.grad[0]}, ${pg.grad[1]})`, overflow: "hidden" }}>
        <div style={{ position: "absolute", inset: 7, border: "1.5px solid rgba(255,255,255,.6)", borderRadius: 5 }} />
        <div style={{ position: "absolute", inset: 12, display: "grid", gridTemplateColumns: two ? "1fr 1fr" : "1fr", gap: 6 }}>
          {Array.from({ length: two ? 2 : 1 }).map((_, k) => <div key={k} style={{ borderRadius: 4, border: "1.5px solid rgba(255,255,255,.85)", background: "rgba(255,255,255,.4)" }} />)}
        </div>
        <div style={{ position: "absolute", left: 0, right: 0, bottom: 5, textAlign: "center", color: "#fff", fontFamily: serif, fontSize: 10.5, fontWeight: 600, textShadow: "0 1px 4px rgba(0,0,0,.3)" }}>{idx === 0 ? t.title : `Trang ${idx + 1}`}</div>
        <div style={{ position: "absolute", top: 0, bottom: 0, [side === "left" ? "right" : "left"]: 0, width: "16%", background: side === "left" ? "linear-gradient(to left, rgba(0,0,0,.16), transparent)" : "linear-gradient(to right, rgba(0,0,0,.16), transparent)" }} />
      </div>
    );
  };
  return (
    <div className="mm-cover" style={{ position: "relative", aspectRatio: "4/3", borderRadius: 14, overflow: "hidden", background: "radial-gradient(120% 90% at 50% 25%, #fbf8f3, #e9e0d2)", display: "grid", placeItems: "center", boxShadow: "0 10px 30px rgba(42,37,32,.12)" }}>
      {/* cuốn sách mở */}
      <div style={{ width: "84%", aspectRatio: "3/2", display: "flex", borderRadius: 6, overflow: "hidden", boxShadow: "0 16px 30px rgba(42,37,32,.28)", transform: "translateY(-2%)" }}>
        {miniPage(s * 2, "left")}
        <div style={{ width: 2, background: "rgba(42,37,32,.18)" }} />
        {miniPage(s * 2 + 1, "right")}
      </div>
      {/* nút play giữa */}
      <button onClick={(e) => { e.stopPropagation(); onPlay(); }} aria-label="Xem flipbook" style={{ position: "absolute", width: 52, height: 52, borderRadius: "50%", background: "rgba(255,255,255,.92)", border: "none", display: "grid", placeItems: "center", cursor: "pointer", boxShadow: "0 6px 18px rgba(42,37,32,.25)" }}><Play size={22} color={C.ink} fill={C.ink} style={{ marginLeft: 3 }} /></button>
      {/* mũi tên */}
      {spreads > 1 && <>
        <button onClick={(e) => move(-1, e)} aria-label="Trước" style={{ ...covArrow, left: 8 }}><ChevronLeft size={18} color={C.ink} /></button>
        <button onClick={(e) => move(1, e)} aria-label="Sau" style={{ ...covArrow, right: 8 }}><ChevronRight size={18} color={C.ink} /></button>
      </>}
      {/* chấm trang */}
      <div style={{ position: "absolute", bottom: 10, left: 0, right: 0, display: "flex", justifyContent: "center", gap: 6 }}>
        {Array.from({ length: spreads }).map((_, k) => <span key={k} style={{ width: k === s ? 16 : 6, height: 6, borderRadius: 999, background: k === s ? C.brass : "rgba(42,37,32,.25)", transition: "all .2s" }} />)}
      </div>
    </div>
  );
}
const covArrow = { position: "absolute", top: "calc(50% - 16px)", width: 32, height: 32, borderRadius: "50%", background: "rgba(255,255,255,.92)", border: "none", display: "grid", placeItems: "center", cursor: "pointer", boxShadow: "0 4px 12px rgba(42,37,32,.2)" };

function StatBox({ icon: Icon, value, label }) {
  return (
    <div style={{ display: "flex", gap: 10, alignItems: "center", padding: "0 18px" }}>
      <Icon size={20} color={C.brass} />
      <div><div style={{ fontFamily: sans, fontSize: 16, fontWeight: 700, color: C.ink, lineHeight: 1.1 }}>{value}</div><div style={{ fontFamily: sans, fontSize: 12, color: C.sub }}>{label}</div></div>
    </div>
  );
}

function Gallery({ go, templates, onOpenAI, onAddCart }) {
  // HOT = top 10 mẫu có lượt dùng nhiều nhất (uses>0), cập nhật liên tục theo dữ liệu
  const hotIds = useMemo(() => new Set(
    [...templates].filter(t => (t.uses || 0) > 0).sort((a, b) => (b.uses || 0) - (a.uses || 0)).slice(0, 10).map(t => t.id)
  ), [templates]);
  // Ưu tiên hiển thị mẫu HOT lên trước
  const ordered = useMemo(() => {
    const hot = templates.filter(t => hotIds.has(t.id)).sort((a, b) => (b.uses || 0) - (a.uses || 0));
    const rest = templates.filter(t => !hotIds.has(t.id));
    return [...hot, ...rest];
  }, [templates, hotIds]);

  return (
    <div style={{ maxWidth: 1200, margin: "0 auto", padding: "38px 22px 70px" }}>
      <Label>Bộ sưu tập</Label>
      <h1 style={{ fontSize: 44, color: C.ink, margin: "8px 0 8px", fontWeight: 700 }}>Mẫu photobook</h1>
      <p style={{ fontFamily: sans, color: C.sub, fontSize: 15.5, maxWidth: 600 }}>Chọn một mẫu — AI điền ảnh của bạn vào các ô có sẵn. Hoặc để AI gợi ý theo mô tả của bạn. <span style={{ color: C.brass, fontWeight: 600 }}>🔥 Mẫu HOT</span> là những mẫu đang được dùng nhiều nhất.</p>

      <div style={{ margin: "22px 0 26px" }}><Btn variant="brass" icon={Wand2} onClick={() => onOpenAI()}>Để AI chọn mẫu giúp tôi</Btn></div>

      {templates.length === 0 ? (
        <div style={{ textAlign: "center", padding: "60px 0", color: C.sub, fontFamily: sans }}>Chưa có mẫu nào. Admin có thể thêm trong khu quản trị.</div>
      ) : (
        <div style={{ display: "grid", gridTemplateColumns: "repeat(4,1fr)", gap: 22 }}>
          {ordered.map((t, i) => {
            const cat = CAT_COLORS[t.category] || [C.cream2, C.sub];
            const priceColor = PRICE_COLORS[i % PRICE_COLORS.length];
            const hot = hotIds.has(t.id);
            return (
              <div key={t.id} className="mm-card mm-rise" style={{ background: C.card, borderRadius: 18, padding: 12, border: `1px solid ${C.line}`, animationDelay: `${Math.min(i, 12) * 0.05}s` }}>
                <div style={{ position: "relative" }}>
                  <GalleryCover t={t} onPlay={() => go("preview", t)} />
                  <span style={{ position: "absolute", top: 12, left: 12, background: cat[0], color: cat[1], borderRadius: 999, padding: "4px 12px", fontFamily: sans, fontSize: 11, fontWeight: 700, letterSpacing: .5, textTransform: "uppercase", zIndex: 3 }}>{t.category}</span>
                  {hot && <span style={{ position: "absolute", top: 12, right: 12, background: "linear-gradient(135deg, #FF7A45, #E8472B)", color: "#fff", borderRadius: 999, padding: "4px 11px", fontFamily: sans, fontSize: 11, fontWeight: 800, display: "flex", gap: 4, alignItems: "center", boxShadow: "0 4px 12px rgba(232,71,43,.35)", zIndex: 3 }}><Flame size={12} fill="#fff" /> HOT</span>}
                </div>
                <div style={{ padding: "12px 4px 4px" }}>
                  <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                    <div style={{ fontFamily: serif, fontSize: 18, color: C.ink, fontWeight: 700 }}>{t.title}</div>
                    <span style={{ fontFamily: sans, fontSize: 13, color: C.sub, display: "flex", gap: 3, alignItems: "center" }}><Star size={13} fill={C.brass} color={C.brass} />{t.rating}</span>
                  </div>
                  <div style={{ display: "flex", gap: 16, margin: "8px 0 8px", fontFamily: sans, fontSize: 12.5, color: C.sub }}>
                    <span style={{ display: "flex", gap: 5, alignItems: "center" }}><BookOpen size={13} /> Photobook</span>
                    <span style={{ display: "flex", gap: 5, alignItems: "center" }}><ImageIcon size={13} /> {t.pageCount} trang</span>
                    {hot && <span style={{ display: "flex", gap: 4, alignItems: "center", color: "#E8472B" }}><Flame size={12} /> {t.uses} lượt dùng</span>}
                  </div>
                  <div style={{ fontFamily: sans, fontSize: 21, color: priceColor, fontWeight: 800, marginBottom: 12 }}>{vnd(minPrice(t.prices))}</div>
                  <div style={{ display: "flex", gap: 8, marginBottom: 8 }}>
                    <Btn full variant="brass" icon={Sparkles} onClick={() => go("design", t)}>Dùng mẫu</Btn>
                    <Btn variant="outline" icon={Eye} onClick={() => go("preview", t)} style={{ padding: "11px 14px" }}>Preview</Btn>
                  </div>
                  <Btn full variant="ghost" icon={ShoppingCart} onClick={() => onAddCart(t)}>Thêm vào giỏ hàng</Btn>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

/* ===================== PREVIEW / FLIPBOOK ===================== */
