                    {p.status === "designed" && <><Btn full variant="brass" icon={ShoppingBag} onClick={() => onBuy(p)}>Mua ngay</Btn><Btn variant="ghost" icon={Trash2} onClick={() => onCancel(p)} /></>}
                    {(p.status === "purchased" || p.status === "shipping") && <Btn full variant="outline" icon={Truck} onClick={() => {}}>Theo dõi đơn</Btn>}
                    {p.status === "delivered" && <Btn full variant="outline" icon={Star} onClick={() => {}}>Đánh giá</Btn>}
                    {p.status === "cancelled" && <Btn full variant="ghost" icon={Sparkles} onClick={() => onContinue(p)}>Thiết kế lại</Btn>}
