/* ===================== CHATBOT ===================== */
function Chatbot({ templates, go }) {
  const [open, setOpen] = useState(false);
  const [input, setInput] = useState("");
  const [msgs, setMsgs] = useState([{ from: "bot", text: "Chào bạn 👋 Bạn muốn làm photobook chủ đề gì? Mình gợi ý mẫu phù hợp." }]);
  const send = () => {
    const text = input.trim(); if (!text) return; setInput("");
    setMsgs(m => [...m, { from: "user", text }]);
    const sugg = matchTemplates(text, templates).filter(s => s.score > 0).slice(0, 4).map(s => s.t);
    setTimeout(() => setMsgs(m => [...m, sugg.length ? { from: "bot", text: `Mình tìm thấy ${sugg.length} mẫu hợp với “${text}”:`, sugg } : { from: "bot", text: "Chưa thấy mẫu khớp. Thử “du lịch”, “gia đình”, “tốt nghiệp” nhé!" }]), 500);
  };
  return (
    <>
      {open && (
        <div style={{ position: "fixed", bottom: 90, right: 24, width: 330, background: C.card, borderRadius: 18, border: `1px solid ${C.line}`, boxShadow: "0 16px 50px rgba(42,37,32,.2)", zIndex: 60, overflow: "hidden" }}>
          <div style={{ background: C.ink, color: "#fff", padding: "14px 16px", display: "flex", justifyContent: "space-between", alignItems: "center" }}><span style={{ fontFamily: serif, fontSize: 16, fontWeight: 600 }}>Trợ lý Memory Makers</span><X size={18} style={{ cursor: "pointer" }} onClick={() => setOpen(false)} /></div>
          <div style={{ padding: 14, height: 300, overflowY: "auto", display: "flex", flexDirection: "column", gap: 10 }}>
            {msgs.map((m, i) => (
              <div key={i} style={{ alignSelf: m.from === "bot" ? "flex-start" : "flex-end", maxWidth: "85%" }}>
                <div style={{ background: m.from === "bot" ? C.cream2 : C.brass, color: m.from === "bot" ? C.ink : "#fff", padding: "8px 12px", borderRadius: 12, fontFamily: sans, fontSize: 13 }}>{m.text}</div>
                {m.sugg && <div style={{ marginTop: 8, display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8 }}>{m.sugg.map(t => (
                  <button key={t.id} onClick={() => { go("preview", t); setOpen(false); }} style={{ textAlign: "left", background: C.card, border: `1px solid ${C.line}`, borderRadius: 10, padding: 6, cursor: "pointer" }}>
                    <div style={{ aspectRatio: "1", borderRadius: 6, overflow: "hidden", background: C.cream2 }}>{(t.demoImage || t.blankImage || t.coverImage) ? <img src={t.demoImage || t.blankImage || t.coverImage} style={{ width: "100%", height: "100%", objectFit: "cover" }} /> : <div style={{ width: "100%", height: "100%", background: `linear-gradient(135deg,${t.grad[0]},${t.grad[1]})` }} />}</div>
                    <div style={{ fontFamily: sans, fontSize: 11, color: C.ink, marginTop: 4, fontWeight: 600 }}>{t.title}</div>
                  </button>))}</div>}
              </div>
            ))}
          </div>
          <div style={{ display: "flex", gap: 8, padding: 12, borderTop: `1px solid ${C.line}` }}>
            <input value={input} onChange={e => setInput(e.target.value)} onKeyDown={e => e.key === "Enter" && send()} placeholder="Nhập chủ đề / prompt…" style={{ flex: 1, border: `1px solid ${C.line}`, borderRadius: 999, padding: "8px 14px", fontFamily: sans, fontSize: 13, outline: "none" }} />
            <button onClick={send} style={{ background: C.ink, border: "none", borderRadius: "50%", width: 36, height: 36, display: "grid", placeItems: "center", cursor: "pointer" }}><Send size={15} color="#fff" /></button>
          </div>
        </div>
      )}
      <button onClick={() => setOpen(o => !o)} className="mm-float" style={{ position: "fixed", bottom: 24, right: 24, width: 56, height: 56, borderRadius: "50%", background: C.brass, border: "none", cursor: "pointer", boxShadow: "0 8px 24px rgba(176,141,87,.4)", display: "grid", placeItems: "center", zIndex: 60 }}><MessageCircle size={24} color="#fff" /></button>
    </>
  );
}

/* ===================== ADMIN: QUẢN LÝ ĐƠN NÂNG CAO ===================== */
function OrderManager({ orders, users, onUpdate }) {
  const [fStatus, setFStatus] = useState("all");
  const [q, setQ] = useState("");
  const stageOpts = ["purchased", "shipping", "delivered", "cancelled"];
  const nameOf = (o) => o.address?.name || users.find(u => u.id === o.owner)?.name || "—";
  const phoneOf = (o) => o.address?.phone || users.find(u => u.id === o.owner)?.phone || "—";
  const list = orders.filter(o => {
    if (fStatus !== "all" && o.status !== fStatus) return false;
    if (!q) return true;
    const s = q.toLowerCase();
    return [o.id, o.tpl.title, nameOf(o), phoneOf(o), o.tracking].some(x => (x || "").toLowerCase().includes(s));
  });
  const counts = { all: orders.length };
  stageOpts.forEach(s => counts[s] = orders.filter(o => o.status === s).length);
  const exportCsv = () => {
    const head = ["Mã đơn", "Khách", "SĐT", "Mẫu", "Loại", "Số tiền", "Trạng thái", "Mã vận đơn", "Địa chỉ", "Thanh toán"];
    const rows = list.map(o => [o.id, nameOf(o), phoneOf(o), o.tpl.title, o.mode === "digital" ? "Digital" : (CATS.find(c => c.id === o.option)?.label || ""), o.amount || 0, STATUSES[o.status].label, o.tracking || "", o.address?.address || "", (o.payMethod || "").toUpperCase()]);
    const esc = v => `"${String(v).replace(/"/g, '""')}"`;
    const csv = "\uFEFF" + [head, ...rows].map(r => r.map(esc).join(",")).join("\n");
    const blob = new Blob([csv], { type: "text/csv;charset=utf-8;" });
    const a = document.createElement("a"); a.href = URL.createObjectURL(blob); a.download = `don-hang-${Date.now()}.csv`; a.click(); URL.revokeObjectURL(a.href);
  };
  const selStyle = { fontFamily: sans, fontSize: 12.5, padding: "5px 8px", borderRadius: 8, border: `1px solid ${C.line}`, background: "#fff", color: C.ink, cursor: "pointer" };
  return (
    <Panel title={`Quản lý đơn hàng (${orders.length})`} action={<Btn variant="ghost" icon={Download} onClick={exportCsv} disabled={!list.length}>Xuất CSV</Btn>}>
      <div style={{ display: "flex", gap: 8, flexWrap: "wrap", marginBottom: 12 }}>
        {[["all", "Tất cả"], ...stageOpts.map(s => [s, STATUSES[s].label])].map(([k, l]) => (
          <button key={k} onClick={() => setFStatus(k)} style={{ fontFamily: sans, fontSize: 12.5, padding: "6px 12px", borderRadius: 999, cursor: "pointer", border: `1px solid ${fStatus === k ? C.ink : C.line}`, background: fStatus === k ? C.ink : "transparent", color: fStatus === k ? C.paper : C.ink }}>{l} ({counts[k] || 0})</button>
        ))}
        <div style={{ flex: 1 }} />
        <div style={{ display: "flex", alignItems: "center", gap: 6, background: "#fff", border: `1px solid ${C.line}`, borderRadius: 999, padding: "4px 12px", minWidth: 220 }}>
          <Search size={15} color={C.sub} />
          <input value={q} onChange={e => setQ(e.target.value)} placeholder="Tìm mã đơn / khách / SĐT / mã vận đơn" style={{ border: "none", outline: "none", fontFamily: sans, fontSize: 13, color: C.ink, background: "transparent", flex: 1 }} />
        </div>
      </div>
      {list.length === 0 ? <div style={{ fontFamily: sans, fontSize: 14, color: C.sub, padding: "14px 0" }}>Không có đơn phù hợp.</div> : (
        <div style={{ overflowX: "auto" }}>
          <table style={{ width: "100%", borderCollapse: "collapse", minWidth: 860 }}>
            <thead><tr>{["Mã đơn", "Khách hàng", "Mẫu", "Loại", "Số tiền", "Trạng thái", "Mã vận đơn", "Địa chỉ"].map(h => <th key={h} style={thStyle}>{h}</th>)}</tr></thead>
            <tbody>{list.map(o => (
              <tr key={o.id} style={{ borderTop: `1px solid ${C.line}` }}>
                <td style={{ ...tdStyle, fontFamily: "monospace", fontSize: 12 }}>{o.id}</td>
                <td style={tdStyle}><div style={{ fontWeight: 600 }}>{nameOf(o)}</div><div style={{ fontSize: 12, color: C.sub }}>{phoneOf(o)}</div></td>
                <td style={tdStyle}>{o.tpl.title}</td>
                <td style={tdStyle}>{o.mode === "digital" ? "Digital" : CATS.find(c => c.id === o.option)?.label}</td>
                <td style={{ ...tdStyle, fontWeight: 700, color: C.brass }}>{vnd(o.amount)}</td>
                <td style={tdStyle}>
                  <select value={o.status} onChange={e => onUpdate(o.id, { status: e.target.value })} style={{ ...selStyle, borderColor: STATUSES[o.status].color, color: STATUSES[o.status].color, fontWeight: 600 }}>
                    {stageOpts.map(s => <option key={s} value={s}>{STATUSES[s].label}</option>)}
                  </select>
                </td>
                <td style={tdStyle}>
                  {o.mode === "digital" ? <span style={{ color: C.sub }}>—</span>
                    : <input value={o.tracking || ""} onChange={e => onUpdate(o.id, { tracking: e.target.value })} placeholder="Nhập mã…" style={{ width: 130, fontFamily: sans, fontSize: 12.5, padding: "5px 8px", borderRadius: 8, border: `1px solid ${C.line}`, outline: "none" }} />}
                </td>
                <td style={{ ...tdStyle, maxWidth: 180, fontSize: 12.5, color: C.sub }}>{o.address?.address || "—"}</td>
              </tr>
            ))}</tbody>
          </table>
        </div>
      )}
    </Panel>
  );
}

/* ===================== ADMIN ===================== */
function Admin({ go, templates, setTemplates, about, setAbout, projects, users, setUsers, currentUser, onUpdateOrder }) {
  const [tab, setTab] = useState("overview");
  const orders = projects.filter(p => ["purchased", "shipping", "delivered", "cancelled"].includes(p.status));
  const revenue = orders.filter(o => o.status !== "cancelled").reduce((s, o) => s + (o.amount || 0), 0);
  const catData = CATS.map(c => ({ ...c, rev: orders.filter(o => o.option === c.id && o.status !== "cancelled").reduce((s, o) => s + (o.amount || 0), 0) }));
  const maxRev = Math.max(...catData.map(c => c.rev), 1);
  const TABS = [["overview", "Tổng quan", TrendingUp], ["orders", "Đơn hàng", ListOrdered], ["addtpl", "Thêm template", Plus], ["products", "Sản phẩm", Package], ["users", "Tài khoản", UsersIcon], ["about", "Trang About", Pencil]];
  return (
    <div style={{ maxWidth: 1200, margin: "0 auto", padding: "28px 22px 70px", display: "grid", gridTemplateColumns: "220px 1fr", gap: 26 }}>
      <aside>
        <div style={{ fontFamily: serif, fontSize: 19, fontWeight: 700, color: C.ink }}>Quản trị</div>
        <div style={{ fontFamily: sans, fontSize: 12, color: C.sub, marginBottom: 16 }}>{currentUser?.email}</div>
        {TABS.map(([k, l, Icon]) => <button key={k} onClick={() => setTab(k)} style={{ width: "100%", textAlign: "left", display: "flex", gap: 10, alignItems: "center", padding: "11px 14px", borderRadius: 10, marginBottom: 6, cursor: "pointer", border: "none", background: tab === k ? C.ink : "transparent", color: tab === k ? C.paper : C.ink, fontFamily: sans, fontSize: 14 }}><Icon size={17} /> {l}</button>)}
        <button onClick={() => go("home")} style={{ marginTop: 12, width: "100%", textAlign: "left", padding: "11px 14px", background: "none", border: "none", color: C.sub, fontFamily: sans, fontSize: 13, cursor: "pointer" }}>← Về trang khách</button>
      </aside>
      <main>
        {tab === "overview" && (
          <>
            <div style={{ display: "grid", gridTemplateColumns: "repeat(4,1fr)", gap: 14, marginBottom: 22 }}>
              {[["Tổng đơn", orders.length, ListOrdered], ["Doanh thu", vnd(revenue), TrendingUp], ["Template", templates.length, Package], ["Khách hàng", users.length, UsersIcon]].map(([l, v, Icon]) => (
                <div key={l} style={{ background: C.card, borderRadius: 14, padding: 16, border: `1px solid ${C.line}` }}><Icon size={18} color={C.brass} /><div style={{ fontFamily: serif, fontSize: 21, color: C.ink, fontWeight: 700, marginTop: 8 }}>{v}</div><div style={{ fontFamily: sans, fontSize: 12, color: C.sub }}>{l}</div></div>
              ))}
            </div>
            <Panel title="Doanh thu theo option">
              {catData.map(c => <div key={c.id} style={{ marginBottom: 14 }}><div style={{ display: "flex", justifyContent: "space-between", fontFamily: sans, fontSize: 14, color: C.ink, marginBottom: 6 }}><span>{c.label}</span><b>{vnd(c.rev)}</b></div><div style={{ height: 12, background: C.cream2, borderRadius: 999 }}><div style={{ width: `${(c.rev / maxRev) * 100}%`, height: "100%", background: C.brass, borderRadius: 999 }} /></div></div>)}
            </Panel>
            <div style={{ height: 18 }} />
            <Panel title="Đơn hàng gần đây" action={<Btn variant="ghost" icon={ListOrdered} onClick={() => setTab("orders")}>Quản lý tất cả</Btn>}>
              {orders.length === 0 ? <div style={{ fontFamily: sans, fontSize: 14, color: C.sub, padding: "10px 0" }}>Chưa có đơn nào.</div> : (
                <table style={{ width: "100%", borderCollapse: "collapse" }}>
                  <thead><tr>{["Mã đơn", "Mẫu", "Loại", "Số tiền", "Trạng thái"].map(h => <th key={h} style={thStyle}>{h}</th>)}</tr></thead>
                  <tbody>{orders.slice(0, 5).map(o => <tr key={o.id} style={{ borderTop: `1px solid ${C.line}` }}><td style={{ ...tdStyle, fontFamily: "monospace", fontSize: 12 }}>{o.id}</td><td style={tdStyle}>{o.tpl.title}</td><td style={tdStyle}>{o.mode === "digital" ? "Digital" : CATS.find(c => c.id === o.option)?.label}</td><td style={tdStyle}>{vnd(o.amount)}</td><td style={tdStyle}><span style={{ background: STATUSES[o.status].color, color: "#fff", borderRadius: 999, padding: "3px 10px", fontSize: 12 }}>{STATUSES[o.status].label}</span></td></tr>)}</tbody>
                </table>
              )}
            </Panel>
          </>
        )}
        {tab === "orders" && <OrderManager orders={orders} users={users} onUpdate={onUpdateOrder} />}
        {tab === "addtpl" && <AddTemplate onAdd={(t) => { setTemplates(ts => [t, ...ts]); setTab("products"); }} />}
        {tab === "products" && (
          <Panel title={`Template (${templates.length})`} action={<Btn variant="brass" icon={Plus} onClick={() => setTab("addtpl")}>Thêm template</Btn>}>
            <div style={{ display: "grid", gridTemplateColumns: "repeat(4,1fr)", gap: 16 }}>
              {templates.map(t => (
                <div key={t.id} style={{ border: `1px solid ${C.line}`, borderRadius: 12, padding: 10 }}>
                  <Cover t={t} kind="cover" />
                  <div style={{ fontFamily: serif, fontSize: 14, color: C.ink, fontWeight: 600, marginTop: 8 }}>{t.title}</div>
                  <div style={{ fontFamily: sans, fontSize: 11, color: C.sub, marginTop: 3 }}>{t.category} · {t.pageCount} trang</div>
                  <div style={{ fontFamily: sans, fontSize: 11, color: C.sub }}>{CATS.map(c => `${t.prices[c.id] / 1000}k`).join(" · ")}</div>
                  <button onClick={() => setTemplates(ts => ts.filter(x => x.id !== t.id))} style={{ marginTop: 8, width: "100%", background: C.cream2, border: "none", borderRadius: 8, padding: "7px", fontFamily: sans, fontSize: 13, color: "#B05A4A", cursor: "pointer", display: "flex", gap: 6, justifyContent: "center", alignItems: "center" }}><Trash2 size={13} /> Xóa</button>
                </div>
              ))}
            </div>
          </Panel>
        )}
        {tab === "users" && <UserManager users={users} setUsers={setUsers} currentUser={currentUser} />}
        {tab === "about" && <AboutEditor about={about} setAbout={setAbout} />}
      </main>
    </div>
  );
}
const thStyle = { textAlign: "left", fontFamily: sans, fontSize: 12, letterSpacing: 1, textTransform: "uppercase", color: C.sub, padding: "0 8px 10px", fontWeight: 700 };
const tdStyle = { padding: "12px 8px", fontFamily: sans, fontSize: 14, color: C.ink };

/* Quản lý tài khoản: xem danh sách + NÚT THÊM ACCOUNT (không phân quyền khách hàng) */
function UserManager({ users, setUsers, currentUser }) {
  const [open, setOpen] = useState(false);
  const [f, setF] = useState({ name: "", email: "", phone: "", password: "", role: "CUSTOMER" });
  const [err, setErr] = useState("");
  const add = () => {
    setErr("");
    if (!f.name || !f.email || !f.phone || !f.password) return setErr("Nhập đủ tên, email, SĐT, mật khẩu.");
    if (!isValidEmail(f.email)) return setErr("Email không hợp lệ.");
    if (users.some(u => u.email === f.email)) return setErr("Email đã tồn tại.");
    setUsers(us => [...us, { id: "u" + Date.now(), name: f.name, email: f.email, phone: f.phone, password: f.password, phoneVerified: true, role: f.role }]);
    setF({ name: "", email: "", phone: "", password: "", role: "CUSTOMER" }); setOpen(false);
  };
  const removeUser = (id) => setUsers(us => us.filter(u => u.id !== id));
  return (
    <Panel title="Tài khoản (Accounts)" action={<Btn variant="brass" icon={Plus} onClick={() => { setOpen(o => !o); setErr(""); }}>Thêm account</Btn>}>
      <p style={{ fontFamily: sans, fontSize: 13, color: C.sub, marginBottom: 14 }}>Danh sách tài khoản hệ thống. Dùng nút “Thêm account” để tạo tài khoản mới.</p>

      {open && (
        <div className="mm-rise" style={{ background: C.cream2, border: `1px solid ${C.line}`, borderRadius: 14, padding: 16, marginBottom: 16 }}>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12 }}>
            <Field label="Họ và tên" value={f.name} onChange={v => setF(s => ({ ...s, name: v }))} placeholder="Nguyễn Văn A" />
            <Field label="Số điện thoại" value={f.phone} onChange={v => setF(s => ({ ...s, phone: v }))} placeholder="09xx xxx xxx" />
            <Field label="Email" value={f.email} onChange={v => setF(s => ({ ...s, email: v }))} placeholder="email@domain.com" />
            <Field label="Mật khẩu" value={f.password} onChange={v => setF(s => ({ ...s, password: v }))} type="password" placeholder="••••••" />
          </div>
          <div style={{ display: "flex", gap: 16, alignItems: "center", flexWrap: "wrap" }}>
            <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
              <span style={{ fontFamily: sans, fontSize: 13, color: C.sub }}>Loại tài khoản:</span>
              {[["CUSTOMER", "Customer"], ["ADMIN", "Admin"]].map(([k, l]) => (
                <button key={k} onClick={() => setF(s => ({ ...s, role: k }))} style={{ fontFamily: sans, fontSize: 13, padding: "6px 14px", borderRadius: 999, cursor: "pointer", border: `1px solid ${f.role === k ? C.brass : C.line}`, background: f.role === k ? C.cream2 : "#fff", color: C.ink, fontWeight: f.role === k ? 700 : 400 }}>{l}</button>
              ))}
            </div>
            <Btn variant="brass" icon={CheckCircle2} onClick={add} style={{ marginLeft: "auto" }}>Tạo tài khoản</Btn>
          </div>
          {err && <div style={{ fontFamily: sans, fontSize: 13, color: "#B05A4A", marginTop: 10 }}>{err}</div>}
        </div>
      )}

      <table style={{ width: "100%", borderCollapse: "collapse" }}>
        <thead><tr>{["Tên", "Email", "SĐT", "Loại", ""].map(h => <th key={h} style={thStyle}>{h}</th>)}</tr></thead>
        <tbody>{users.map(u => (
          <tr key={u.id} style={{ borderTop: `1px solid ${C.line}` }}>
            <td style={tdStyle}>{u.name}{currentUser?.id === u.id && <span style={{ color: C.brass }}> (bạn)</span>}</td>
            <td style={tdStyle}>{u.email}</td>
            <td style={tdStyle}>{u.phone} {u.phoneVerified && "✓"}</td>
            <td style={tdStyle}><span style={{ background: u.role === "ADMIN" ? C.brass : C.cream2, color: u.role === "ADMIN" ? "#fff" : C.ink, borderRadius: 999, padding: "3px 10px", fontSize: 12 }}>{u.role === "ADMIN" ? "Admin" : "Customer"}</span></td>
            <td style={tdStyle}>{u.id !== currentUser?.id
              ? <button onClick={() => removeUser(u.id)} style={{ background: "none", border: "none", cursor: "pointer", color: "#B05A4A", fontFamily: sans, fontSize: 12.5, display: "flex", gap: 4, alignItems: "center" }}><Trash2 size={13} /> Xoá</button>
              : <span style={{ fontFamily: sans, fontSize: 12, color: C.sub }}>—</span>}</td>
          </tr>
        ))}</tbody>
      </table>
    </Panel>
  );
}
const roleBtn = (disabled, color) => ({ fontFamily: sans, fontSize: 13, border: `1px solid ${color}`, color, background: "transparent", borderRadius: 999, padding: "6px 12px", cursor: disabled ? "not-allowed" : "pointer", opacity: disabled ? 0.3 : 1 });

function AddTemplate({ onAdd }) {
  const [form, setForm] = useState({ title: "", desc: "", category: "", slots: "4", keywords: "", canvaLink: "", featured: false, soft: "290000", hard: "450000", fan: "520000", digital: "150000" });
  const [pages, setPages] = useState([]);      // [{image, slots}]
  const [detecting, setDetecting] = useState(false);
  const pagesRef = useRef();
  const addPages = async (e) => {
    const files = Array.from(e.target.files || []); if (!files.length) return;
    setDetecting(true);
    for (const f of files) {
      const dataUrl = await new Promise(res => { const r = new FileReader(); r.onload = () => res(r.result); r.readAsDataURL(f); });
      const slots = await autoDetectSlots(dataUrl);   // TỰ ĐO & TẠO KHUNG
      setPages(p => [...p, { image: dataUrl, slots }]);
    }
    setDetecting(false); e.target.value = "";
  };
  const totalAuto = pages.reduce((s, p) => s + p.slots.length, 0);
  const submit = () => {
    const hasPages = pages.length > 0;
    const slots = hasPages ? totalAuto : Math.max(1, parseInt(form.slots) || 4);
    onAdd({
      id: "t" + Date.now(), title: form.title, slug: slugify(form.title) + "-" + Date.now().toString(36),
      desc: form.desc || "Mẫu mới do admin thêm.", category: form.category || "Khác",
      keywords: form.keywords.split(",").map(s => s.trim().toLowerCase()).filter(Boolean),
      grad: GRADS[Math.floor(Math.random() * GRADS.length)],
      blankImage: null, demoImage: null,
      coverImage: hasPages ? pages[0].image : null,   // bìa = trang đầu
      previewGif: null, previewVideo: null,
      pages: hasPages ? pages : null,
      canvaLink: form.canvaLink, slots, pageCount: hasPages ? pages.length : Math.ceil(slots / 2),
      prices: { soft: +form.soft, hard: +form.hard, fan: +form.fan, digital: +form.digital },
      rating: "5.0", uses: 0, featured: form.featured,
    });
  };
  return (
    <Panel title="Thêm template mới">
      {/* Tải các trang — TỰ ĐỘNG TẠO KHUNG CHÈN ẢNH (trang 1 = bìa trước, trang cuối = bìa sau) */}
      <div style={{ border: `1.5px solid ${C.line}`, borderRadius: 14, padding: 16, marginBottom: 18, background: C.cream2 }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", flexWrap: "wrap", gap: 10 }}>
          <div>
            <div style={{ fontFamily: serif, fontSize: 16, fontWeight: 700, color: C.ink, display: "flex", gap: 7, alignItems: "center" }}><Wand2 size={16} color={C.brass} /> Tải các trang — tự tạo khung chèn ảnh</div>
            <div style={{ fontFamily: sans, fontSize: 12.5, color: C.sub, marginTop: 3 }}>Mỗi ảnh = 1 trang. Hệ thống tự dò vùng đặt ảnh và tạo khung. Trang đầu là bìa trước, trang cuối là bìa sau. {pages.length > 0 && <b style={{ color: C.brass }}>{pages.length} trang</b>}</div>
          </div>
          <div style={{ display: "flex", gap: 8 }}>
            {pages.length > 0 && <Btn variant="ghost" icon={Trash2} onClick={() => setPages([])}>Xoá hết</Btn>}
            <Btn variant="brass" icon={detecting ? undefined : Plus} onClick={() => pagesRef.current?.click()} disabled={detecting}>{detecting ? "Đang dò khung…" : "Tải ảnh trang"}</Btn>
          </div>
          <input ref={pagesRef} type="file" accept="image/*" multiple onChange={addPages} style={{ display: "none" }} />
        </div>
        {pages.length > 0 && (
          <div style={{ display: "grid", gridTemplateColumns: "repeat(6,1fr)", gap: 8, marginTop: 12 }}>
            {pages.map((p, i) => (
              <div key={i} style={{ position: "relative", borderRadius: 8, overflow: "hidden", border: `1px solid ${C.line}`, background: "#fff" }}>
                <div style={{ position: "relative" }}>
                  <img src={p.image} style={{ width: "100%", display: "block" }} />
                  {p.slots.map((s, k) => <div key={k} style={{ position: "absolute", left: s.x + "%", top: s.y + "%", width: s.w + "%", height: s.h + "%", border: `2px solid ${C.brass}`, borderRadius: s.shape === "circle" ? "50%" : 3, background: "rgba(176,141,87,.18)" }} />)}
                </div>
                <div style={{ fontFamily: sans, fontSize: 10.5, color: C.sub, textAlign: "center", padding: "3px 0" }}>{i === 0 ? "Bìa trước" : i === pages.length - 1 ? "Bìa sau" : `Trang ${i + 1}`} · {p.slots.length} khung</div>
                <button onClick={() => setPages(ps => ps.filter((_, j) => j !== i))} style={{ position: "absolute", top: 3, right: 3, background: "rgba(42,37,32,.7)", border: "none", borderRadius: "50%", width: 20, height: 20, display: "grid", placeItems: "center", cursor: "pointer" }}><X size={11} color="#fff" /></button>
              </div>
            ))}
          </div>
        )}
      </div>

      <Field label="Tiêu đề" value={form.title} onChange={v => setForm(f => ({ ...f, title: v }))} placeholder="vd: Hành trình mùa hè" />
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12 }}>
        <Field label="Danh mục" value={form.category} onChange={v => setForm(f => ({ ...f, category: v }))} placeholder="Du lịch" />
        <Field label="Số trang (tự đếm)" value={pages.length > 0 ? String(pages.length) : form.slots} onChange={v => setForm(f => ({ ...f, slots: v }))} type="number" style={pages.length > 0 ? { background: C.cream2 } : {}} />
      </div>
      <Field label="Mô tả" value={form.desc} onChange={v => setForm(f => ({ ...f, desc: v }))} area={2} />
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12 }}>
        <Field label="Từ khóa (phẩy)" value={form.keywords} onChange={v => setForm(f => ({ ...f, keywords: v }))} placeholder="du lịch, biển" />
        <Field label="Link Canva" value={form.canvaLink} onChange={v => setForm(f => ({ ...f, canvaLink: v }))} placeholder="https://canva.com/..." />
      </div>
      <Label>Giá theo option</Label>
      <div style={{ display: "grid", gridTemplateColumns: "repeat(4,1fr)", gap: 12, marginTop: 10 }}>
        <Field label="Bìa thường" value={form.soft} onChange={v => setForm(f => ({ ...f, soft: v }))} type="number" />
        <Field label="Bìa cứng" value={form.hard} onChange={v => setForm(f => ({ ...f, hard: v }))} type="number" />
        <Field label="Gấp quạt" value={form.fan} onChange={v => setForm(f => ({ ...f, fan: v }))} type="number" />
        <Field label="Digital" value={form.digital} onChange={v => setForm(f => ({ ...f, digital: v }))} type="number" />
      </div>
      <label style={{ display: "flex", gap: 8, alignItems: "center", fontFamily: sans, fontSize: 14, color: C.ink, marginBottom: 14 }}><input type="checkbox" checked={form.featured} onChange={e => setForm(f => ({ ...f, featured: e.target.checked }))} /> Mẫu nổi bật</label>
      <Btn variant="brass" icon={Plus} onClick={submit} disabled={!form.title || detecting}>Thêm template</Btn>
    </Panel>
  );
}
function AboutEditor({ about, setAbout }) {
  const [f, setF] = useState(about); const [saved, setSaved] = useState(false);
  return (
    <Panel title="Chỉnh sửa trang About" action={<Btn variant="brass" icon={CheckCircle2} onClick={() => { setAbout(f); setSaved(true); }}>{saved ? "Đã lưu" : "Lưu thay đổi"}</Btn>}>
      <Field label="Tiêu đề lớn" value={f.headline} onChange={v => { setF(s => ({ ...s, headline: v })); setSaved(false); }} />
      <Field label="Sứ mệnh" value={f.mission} onChange={v => { setF(s => ({ ...s, mission: v })); setSaved(false); }} area={3} />
      <Field label="Câu chuyện" value={f.story} onChange={v => { setF(s => ({ ...s, story: v })); setSaved(false); }} area={4} />
      <Field label="Giá trị" value={f.values} onChange={v => { setF(s => ({ ...s, values: v })); setSaved(false); }} area={4} />
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 12 }}>
        <Field label="Instagram" value={f.instagram} onChange={v => { setF(s => ({ ...s, instagram: v })); setSaved(false); }} />
        <Field label="TikTok" value={f.tiktok} onChange={v => { setF(s => ({ ...s, tiktok: v })); setSaved(false); }} />
        <Field label="Hotline" value={f.hotline} onChange={v => { setF(s => ({ ...s, hotline: v })); setSaved(false); }} />
      </div>
    </Panel>
  );
}
function Panel({ title, action, children }) {
  return <div style={{ background: C.card, borderRadius: 16, border: `1px solid ${C.line}`, padding: 22 }}><div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}><h3 style={{ fontSize: 20, color: C.ink, fontWeight: 700, margin: 0 }}>{title}</h3>{action}</div>{children}</div>;
}

/* ===================== ROOT ===================== */
const DEFAULT_ABOUT = {
  headline: "Mỗi cuốn sách là một lần được sống lại khoảnh khắc.",
  mission: "Memory Makers giúp những kỷ niệm rời rạc trong điện thoại trở thành một vật phẩm có thể chạm vào. Sứ mệnh: lưu giữ câu chuyện của bạn bằng thiết kế tử tế và công nghệ AI thân thiện.",
  story: "Bắt đầu từ một nhóm bạn mê chụp ảnh nhưng tiếc những khoảnh khắc chỉ nằm im trong điện thoại, Memory Makers ra đời để biến ảnh thành sách — dễ dàng, nhanh chóng và đẹp.",
  values: "• Mẫu thiết kế sẵn, AI chỉ thay ảnh vào khung — giữ nguyên 100% bố cục.\n• Bảo vệ hình ảnh khách trước khi thanh toán.\n• In ấn chất lượng cao, giao tận nơi, hỗ trợ COD.",
  instagram: "@memorymakers", tiktok: "TikTok @memorymakers", hotline: "Hotline 09xx xxx xxx",
};
const SEED_USERS = [
  { id: "admin1", name: "Chủ shop (bạn)", email: "admin@memorymakers.com", password: "admin123", phone: "0900000000", phoneVerified: true, role: "ADMIN" },
  { id: "cus1", name: "Trần Thu Hà", email: "ha@gmail.com", password: "123456", phone: "0912345678", phoneVerified: true, role: "CUSTOMER" },
  { id: "cus2", name: "Lê Minh Quân", email: "quan@gmail.com", password: "123456", phone: "0987654321", phoneVerified: true, role: "CUSTOMER" },
];
// Không tạo đơn ảo — khu quản trị chỉ hiển thị đơn hàng thật do khách đặt trong phiên.
const SEED_PROJECTS = [];

export default function App() {
  const [view, setView] = useState("home");
  const [arg, setArg] = useState(null);
  const [user, setUser] = useState(null);
  const [users, setUsers] = useState(SEED_USERS);
  const [templates, setTemplates] = useState(SEED_TEMPLATES);
  const [about, setAbout] = useState(DEFAULT_ABOUT);
  const [projects, setProjects] = useState(SEED_PROJECTS);
  const [cart, setCart] = useState([]);
  const [checkoutItems, setCheckoutItems] = useState([]);
  const [aiOpen, setAiOpen] = useState(false);
  const [aiInitial, setAiInitial] = useState("");
  const [pendingDesign, setPendingDesign] = useState(null);

  const onOpenAI = (initial = "") => { setAiInitial(typeof initial === "string" ? initial : ""); setAiOpen(true); };
  useEffect(() => { if (user) { const u = users.find(x => x.id === user.id); if (u && u.role !== user.role) setUser(u); } }, [users, user]);

  const go = (v, a = null) => {
    if (v === "design") { if (!user) { setPendingDesign(a); setView("auth"); return; } setArg(a); }
    else if (v === "preview") setArg(a);
    setView(v);
    if (typeof window !== "undefined") window.scrollTo(0, 0);
  };
  const onLogin = (u) => { setUser(u); if (pendingDesign) { const t = pendingDesign; setPendingDesign(null); setArg(t); setView("design"); } else setView("account"); };
  const onLogout = () => { setUser(null); setView("home"); };

  const saveProject = ({ tpl, photos, status }) => {
    const id = "p" + Date.now();
    setProjects(ps => [{ id, owner: user?.id, tpl, photos, status: status || "designing", mode: null, option: null, amount: null, address: null }, ...ps]);
    setTemplates(ts => ts.map(t => t.id === tpl.id ? { ...t, uses: (t.uses || 0) + 1 } : t)); // tăng lượt dùng -> cập nhật HOT
    return id;
  };
  const updateProject = (id, patch) => setProjects(ps => ps.map(p => p.id === id ? { ...p, ...patch } : p));
  const myProjects = projects.filter(p => p.owner === user?.id);

  const addToCart = (it) => { setCart(c => c.some(x => x.projectId === it.projectId) ? c : [...c, it]); setView("cart"); window.scrollTo(0, 0); };
  // Thêm từ thẻ kho mẫu: thêm vào giỏ nhưng CHƯA thiết kế — phải thiết kế ảnh xong mới thanh toán được.
  const addTemplateToCart = (tpl) => {
    const opt = ["soft", "hard", "fan"].reduce((a, b) => tpl.prices[b] < tpl.prices[a] ? b : a, "hard");
    const item = { projectId: "c" + Date.now(), tpl, mode: "physical", option: opt, amount: tpl.prices[opt], photos: [], quick: true };
    setCart(c => [...c, item]); setView("cart"); window.scrollTo(0, 0);
  };
  // Thiết kế cho 1 mục trong giỏ: bỏ mục chưa thiết kế rồi vào trình thiết kế (xong sẽ thêm lại bản đã thiết kế).
  const designFromCart = (item) => { setCart(c => c.filter(x => x.projectId !== item.projectId)); go("design", item.tpl); };
  const buyNow = (it) => { setCheckoutItems([it]); setView("checkout"); window.scrollTo(0, 0); };
  const checkoutCart = (items) => {
    if (items.some(it => it.quick)) return; // chặn: còn mẫu chưa thiết kế
    setCheckoutItems(items); setView("checkout"); window.scrollTo(0, 0);
  };
  const completeCheckout = ({ method, address }) => {
    const ids = new Set(checkoutItems.map(i => i.projectId));
    checkoutItems.forEach(it => {
      const patch = { mode: it.mode, option: it.option, amount: it.amount, status: "purchased", address: it.mode === "physical" ? address : null, payMethod: method };
      if (projects.some(p => p.id === it.projectId)) updateProject(it.projectId, patch);
      else setProjects(ps => [{ id: it.projectId, owner: user?.id, tpl: it.tpl, photos: it.photos || [], ...patch }, ...ps]); // mục thêm từ thẻ -> tạo đơn mới
    });
    setCart(c => c.filter(x => !ids.has(x.projectId)));
    setCheckoutItems([]);
  };

  return (
    <div style={{ background: C.paper, minHeight: "100vh", color: C.ink }}>
      <style>{`@import url('https://fonts.googleapis.com/css2?family=Be+Vietnam+Pro:wght@400;500;600;700&family=Lora:ital,wght@0,400;0,500;0,600;0,700;1,400;1,600&display=swap');
        * { -webkit-font-smoothing: antialiased; -moz-osx-font-smoothing: grayscale; box-sizing: border-box; }
        body { margin: 0; font-family: 'Be Vietnam Pro', ui-sans-serif, system-ui, sans-serif; color: #2A2520; line-height: 1.65; font-size: 16px; letter-spacing: .1px; }
        h1, h2, h3 { font-family: 'Lora', Georgia, serif; letter-spacing: -0.015em; line-height: 1.14; text-wrap: balance; }
        p { text-wrap: pretty; }
        input, textarea, button { font-family: inherit; }
        ::selection { background: #E8C9C1; color: #2A2520; }
        ::placeholder { color: #A89E90; }
        .mm-strip::-webkit-scrollbar { display: none; }
        @keyframes mmPageIn { from { opacity: 0; transform: translateY(14px); } to { opacity: 1; transform: translateY(0); } }
        @keyframes mmRise { from { opacity: 0; transform: translateY(20px); } to { opacity: 1; transform: translateY(0); } }
        @keyframes mmPop { 0% { opacity: 0; transform: scale(.92); } 60% { transform: scale(1.02); } 100% { opacity: 1; transform: scale(1); } }
        @keyframes mmFloat { 0%,100% { transform: translateY(0); } 50% { transform: translateY(-8px); } }
        @keyframes mmFadeIn { from { opacity: 0; } to { opacity: 1; } }
        @keyframes mmTurnShade { 0% { opacity: 0; } 35% { opacity: .55; } 70% { opacity: .3; } 100% { opacity: 0; } }
        .mm-shade { animation: mmTurnShade .72s ease both; }
        .mm-page { animation: mmPageIn .5s cubic-bezier(.2,.7,.2,1) both; }
        .mm-rise { animation: mmRise .55s cubic-bezier(.2,.7,.2,1) both; }
        .mm-pop  { animation: mmPop .45s cubic-bezier(.2,.7,.2,1) both; }
        .mm-cover { transition: transform .4s cubic-bezier(.2,.7,.2,1), box-shadow .4s ease; will-change: transform; }
        .mm-cover:hover { transform: translateY(-5px) scale(1.025); box-shadow: 0 22px 48px rgba(42,37,32,.24); }
        .mm-btn { transition: transform .18s ease, box-shadow .2s ease, filter .2s ease; }
        .mm-btn:hover { transform: translateY(-2px); filter: brightness(1.06); box-shadow: 0 8px 20px rgba(42,37,32,.16); }
        .mm-btn:active { transform: translateY(0) scale(.96); }
        .mm-card { transition: transform .35s cubic-bezier(.2,.7,.2,1), box-shadow .35s ease; }
        .mm-card:hover { transform: translateY(-6px); box-shadow: 0 22px 46px rgba(42,37,32,.16); }
        .mm-nav { position: relative; }
        .mm-nav::after { content: ''; position: absolute; left: 0; bottom: -5px; height: 2px; width: 0; background: #B08D57; transition: width .26s ease; }
        .mm-nav:hover::after { width: 100%; }
        .mm-arrow { transition: box-shadow .2s ease, background .2s ease, transform .2s ease; }
        .mm-arrow:hover { background: #B08D57; box-shadow: 0 10px 26px rgba(176,141,87,.4); }
        .mm-arrow:hover svg { stroke: #fff; }
        .mm-float { animation: mmFloat 3.4s ease-in-out infinite; }
        @keyframes mmTwinkle { 0%,100% { opacity:.45; transform: scale(.6); } 50% { opacity:1; transform: scale(1.15); } }
        @keyframes mmDraw { to { stroke-dashoffset: 0; } }
        .mm-mark { transition: transform .5s cubic-bezier(.2,.7,.2,1); }
        .mm-logo:hover .mm-mark { transform: rotate(-7deg) scale(1.06); }
        .mm-twinkle { transform-origin: 35.5px 13.2px; animation: mmTwinkle 3s ease-in-out infinite; }
        .mm-swash { stroke-dasharray: 175; stroke-dashoffset: 175; animation: mmDraw 1.2s ease .25s forwards; }
        .mm-logo:hover .mm-swash { animation: mmDraw .7s ease forwards; }
        .mm-caticon { transition: transform .35s cubic-bezier(.2,.7,.2,1); }
        .mm-card:hover .mm-caticon { transform: rotate(-8deg) scale(1.1); }
        @media (prefers-reduced-motion: reduce) { .mm-page,.mm-rise,.mm-pop,.mm-float { animation: none !important; } .mm-cover:hover,.mm-card:hover,.mm-btn:hover { transform: none !important; } }`}</style>

      {view !== "admin" && <Header go={go} user={user} onLogout={onLogout} onOpenAI={onOpenAI} cartCount={cart.length} />}

      <div className="mm-page" key={view}>
        {view === "home" && <Home go={go} templates={templates} about={about} onOpenAI={onOpenAI} />}
        {view === "gallery" && <Gallery go={go} templates={templates} onOpenAI={onOpenAI} onAddCart={addTemplateToCart} />}
        {view === "preview" && arg && <Preview go={go} t={arg} />}
        {view === "about" && <About about={about} go={go} />}
        {view === "policy" && <Policy go={go} />}
        {view === "auth" && <Auth users={users} setUsers={setUsers} onLogin={onLogin} go={go} />}
        {view === "account" && (user
          ? <MyProjects projects={myProjects} go={go} onContinue={(p) => go("design", p.tpl)} onBuy={(p) => go("design", p.tpl)} onCancel={(p) => updateProject(p.id, { status: "cancelled" })} />
          : <Auth users={users} setUsers={setUsers} onLogin={onLogin} go={go} />)}
        {view === "design" && arg && <DesignFlow tpl={arg} user={user} onSaveProject={saveProject} onAddToCart={addToCart} onBuyNow={buyNow} go={go} />}
        {view === "cart" && <Cart cart={cart} go={go} onRemove={(id) => setCart(c => c.filter(x => x.projectId !== id))} onCheckout={checkoutCart} onDesign={designFromCart} />}
        {view === "checkout" && <Checkout items={checkoutItems} go={go} onComplete={completeCheckout} />}
        {view === "admin" && user?.role === "ADMIN" && <Admin go={go} templates={templates} setTemplates={setTemplates} about={about} setAbout={setAbout} projects={projects} users={users} setUsers={setUsers} currentUser={user} onUpdateOrder={updateProject} />}
      </div>

      {aiOpen && <AIDesignModal templates={templates} initialPrompt={aiInitial} onClose={() => setAiOpen(false)} onUse={(t) => { setAiOpen(false); go("design", t); }} />}
      {view !== "admin" && <Chatbot templates={templates} go={go} />}
    </div>
  );
}
